#include <unistd.h>
#include <stdio.h>
#include <stdlib.h>

int main() {
 pid_t pid = fork();

 if (pid == 0) {
 // Child process - replace with ls -l
 execl("/bin/ls", "ls", "-l", NULL);
 // If execl returns, it failed
 perror("execl failed");
 exit(1);
 } else if (pid > 0) {
 // Parent process waits
 wait(NULL);
 printf("Child completed\n");
 } else {
 perror("fork failed");
 }
 return 0;
}

#include <unistd.h>
