 char *args[] = {"ls", "-l", "-a", NULL};

 pid_t pid = fork();

 if (pid == 0) {
 // Child - execvp searches PATH for 'ls'
 execvp("ls", args);
 perror("execvp failed");
 exit(1);
 } else if (pid > 0) {
 wait(NULL);
 }
 return 0;
}

#include <unistd.h>
#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int main() {
 int pipe1[2], pipe2[2];
 char read_msg[100];

 // Create two pipes for bidirectional communication
 pipe(pipe1); // Parent to Child
 pipe(pipe2); // Child to Parent

 pid_t pid = fork();

 if (pid == 0) {
 // Child process
 close(pipe1[1]); // Close write end of pipe1
 close(pipe2[0]); // Close read end of pipe2

 read(pipe1[0], read_msg, 100);
 printf("Child received: %s\n", read_msg);

 write(pipe2[1], "Hello from Child!", 17);

 close(pipe1[0]);
 close(pipe2[1]);
 } else {
 // Parent process
 close(pipe1[0]); // Close read end of pipe1
 close(pipe2[1]); // Close write end of pipe2

 write(pipe1[1], "Hello from Parent!", 17);

 read(pipe2[0], read_msg, 100);
 printf("Parent received: %s\n", read_msg);

 close(pipe1[1]);
 close(pipe2[0]);
 wait(NULL);
 }
 return 0;
}

