#include <sys/ipc.h>
#include <sys/shm.h>
#include <sys/sem.h>
#include <stdio.h>
#include <stdlib.h>

union semun {
 int val;
 struct semid_ds *buf;
 unsigned short *array;
};

int main() {
 // Create shared memory segment
 int shmid = shmget(IPC_PRIVATE, 1024, IPC_CREAT | 0666);
 char *shm_ptr = (char *)shmat(shmid, NULL, 0);

 // Create semaphore set with 1 semaphore
 int semid = semget(IPC_PRIVATE, 1, IPC_CREAT | 0666);
 union semun arg;
 arg.val = 1; // Binary semaphore (mutex)
 semctl(semid, 0, SETVAL, arg);

 // Semaphore operations
 struct sembuf wait_op = {0, -1, 0}; // wait() / P operation
 struct sembuf signal_op = {0, 1, 0}; // signal() / V operation

 pid_t pid = fork();

 if (pid == 0) {
 // Child: acquire semaphore, write, release
 semop(semid, &wait_op, 1);
 sprintf(shm_ptr, "Written by child");
 semop(semid, &signal_op, 1);
 } else {
 // Parent: acquire semaphore, read, release
 semop(semid, &wait_op, 1);
 printf("Parent read: %s\n", shm_ptr);
 semop(semid, &signal_op, 1);
 wait(NULL);

 // Cleanup
 shmdt(shm_ptr);
 shmctl(shmid, IPC_RMID, NULL);
 semctl(semid, 0, IPC_RMID);
 }
 return 0;
}

#include <unistd.h>
#include <stdio.h>
#include <stdlib.h>

int main() {
 char *args[] = {"env", NULL};

 // Custom environment - only these variables will be set
 char *env[] = {
 "MY_CUSTOM_VAR=HelloWorld",
 "USER=customuser",
 NULL
 };

 pid_t pid = fork();

 if (pid == 0) {
 // execve is the only function accepting custom environment
 execve("/usr/bin/env", args, env);
 perror("execve failed");
 exit(1);
 } else if (pid > 0) {
 wait(NULL);
 }
 return 0;
}
